1	interface PolicyItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	const ITEM_PREMIUMS: Record<string, number> = {
8	  Sword: 100,
9	  Amulet: 60,
10	  Staff: 80,
11	  Potion: 40,
12	};
13	
14	const PROCESSING_FEE = 5;
15	const DEFAULT_PREMIUM = 100;
16	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
17	const HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER = 1.3;
18	const HIGH_ENCHANTMENT_THRESHOLD = 5;
19	
20	const applyItemSurcharges = (item: PolicyItem): number => {
21	  const basePremium = ITEM_PREMIUMS[item.type] ?? DEFAULT_PREMIUM;
22	  const cursedMultiplier = item.cursed ? CURSED_SURCHARGE_MULTIPLIER : 1;
23	  const enchantmentMultiplier = item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
24	    ? HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER
25	    : 1;
26	  return basePremium * cursedMultiplier * enchantmentMultiplier;
27	};
28	
29	interface Customer {
30	  yearsAsCustomer?: number;
31	  isFollowUpQuote?: boolean;
32	}
33	
34	const LOYALTY_DISCOUNT_MULTIPLIER = 0.8;
35	const LOYALTY_DISCOUNT_THRESHOLD = 2;
36	const FIRST_INSURANCE_SURCHARGE_MULTIPLIER = 1.1;
37	const FOLLOW_UP_QUOTE_DISCOUNT_MULTIPLIER = 0.85;
38	
39	const applyCustomerModifier = (basePremium: number, customer?: Customer): number => {
40	  if (customer?.isFollowUpQuote) {
41	    return basePremium * FOLLOW_UP_QUOTE_DISCOUNT_MULTIPLIER;
42	  }
43	  if (customer?.yearsAsCustomer === 0) {
44	    return basePremium * FIRST_INSURANCE_SURCHARGE_MULTIPLIER;
45	  }
46	  if (customer?.yearsAsCustomer !== undefined && customer.yearsAsCustomer >= LOYALTY_DISCOUNT_THRESHOLD) {
47	    return basePremium * LOYALTY_DISCOUNT_MULTIPLIER;
48	  }
49	  return basePremium;
50	};
51	
52	export function calculatePremium(policy: unknown[], customer?: Customer): number {
53	  const items = policy as PolicyItem[];
54	  let basePremium = items.reduce((sum, item) => sum + applyItemSurcharges(item), 0);
55	  basePremium = applyCustomerModifier(basePremium, customer);
56	  return Math.round(basePremium + PROCESSING_FEE);
57	}
